#include "timer.h"
#include "tmpfs.h"
#include "virtio_blk.h"

static bool mount_root_filesystem(void) {
    if (!virtio_blk_init()) {
        return false;
    }

    if (ext4_probe()) {
        return vfs_mount_root("/dev/vda", "ext4", 0, 0) == 0;
    }
    return false;
}

static void mount_procfs(void) {
    int ret;

    /*
     * procfs is expected to exist early so /proc paths resolve to the
     * procfs inode/file operations instead of the generic root placeholder.
     */
    ret = vfs_create_file("/proc", S_IFDIR | 0555U);
    if (ret != 0 && ret != -EEXIST) {
        kputs("procfs: failed to create /proc mountpoint\n");
        return;
    }

    ret = sys_mount(0, "/proc", "procfs", 0, 0);
    if (ret != 0 && ret != -EBUSY) {
        kputs("procfs: failed to mount /proc\n");
    }
}

#ifdef ARCH_RISCV
void riscv_kernel_trap_init(void);
#endif

void kmain(uint64_t boot_arg0, uint64_t boot_arg1, uint64_t boot_arg2) {
    (void)boot_arg0;
    (void)boot_arg1;
    (void)boot_arg2;

#ifdef ARCH_RISCV
    riscv_kernel_trap_init();
#endif
    mm_init();
    vfs_init();
    platform_paging_init();
    (void)mount_root_filesystem();
    devfs_init();
    mount_procfs();
    tmpfs_init();
    proc_system_init();
    timer_system_init();
    (void)ext4_run_test_scripts();

    platform_shutdown();
}

