enum process_fd_kind {
    PROCESS_FD_NONE = 0,
    PROCESS_FD_CONSOLE,
    PROCESS_FD_TEXT,
    PROCESS_FD_FILE,
    PROCESS_FD_DIR,
    PROCESS_FD_EXT4_FILE,
    PROCESS_FD_PIPE_READ,
    PROCESS_FD_PIPE_WRITE,
    PROCESS_FD_DEV,
    PROCESS_FD_DEV_DIR,
    PROCESS_FD_PROC_DIR,
    PROCESS_FD_PROC_FILE,
    PROCESS_FD_SOCKET,
};

enum proc_state {
    PROC_UNUSED = 0,
    PROC_READY,
    PROC_RUNNING,
    PROC_WAITING,
    PROC_ZOMBIE,
    PROC_DEAD,
};

struct kernel_context {
    uint64_t sp;
    uint64_t ra;
    uint64_t s0;
    uint64_t s1;
    uint64_t s2;
    uint64_t s3;
    uint64_t s4;
    uint64_t s5;
    uint64_t s6;
    uint64_t s7;
    uint64_t s8;
    uint64_t s9;
    uint64_t s10;
    uint64_t s11;
};

enum { PROC_MAX_PROCS = 64U };
enum { PROC_KSTACK_PAGES = 4U };
enum { PROC_KSTACK_BYTES = PROC_KSTACK_PAGES * 4096U };
enum { PROC_MMAP_MAX = 512U };
enum { PROC_PIPE_MAX = 128U };
enum { PROC_PIPE_BUF_SIZE = 4096U };
enum { PROC_MEM_FILE_MAX = 128U };
enum { PROC_MEM_FILE_PATH_MAX = 96U };
enum { PROC_MEM_FILE_DATA_MAX = 512U };
enum { PROC_MEM_FILE_PATTERN_GRANULE = 1024U };
enum { PROC_MEM_FILE_PATTERN_MAX = 4096U };
enum { PROC_SIGNAL_MAX = 64U };
enum { PROC_SIGCHLD = 17U };
enum { PROC_MAX_FD = 128U };

struct proc_mmap_region {
    uint8_t fd_kind;
    uint64_t start;
    uint64_t len;
    uint64_t flags;
    uint64_t file_offset;
    uint64_t pte_flags;
    uint64_t mmap_flags;
    struct file* file;
};

struct proc_pipe {
    uint8_t used;
    uint8_t read_open;
    uint8_t write_open;
    uint64_t head;
    uint64_t len;
    char data[PROC_PIPE_BUF_SIZE];
};

struct proc_mem_file {
    uint8_t used;
    uint8_t is_dir;
    uint16_t reserved;
    uint32_t mode;
    uint64_t len;
    char path[PROC_MEM_FILE_PATH_MAX];
    char data[PROC_MEM_FILE_DATA_MAX];
    uint8_t pattern_valid[PROC_MEM_FILE_PATTERN_MAX];
    uint8_t pattern_byte[PROC_MEM_FILE_PATTERN_MAX];
};

extern struct proc_mem_file proc_mem_file_table[PROC_MEM_FILE_MAX];
long kernel_get_proc_cmdline(unsigned long pid, char *buf, size_t len, size_t offset);

struct proc_signal_action {
    uint64_t handler;
    uint64_t flags;
    uint64_t restorer;
    uint64_t mask;
};

struct proc {
    enum proc_state state;
    struct user_space *space;
    struct kernel_context context;
    void *trap_frame_page;
    uint64_t trap_frame_va;
    uint8_t kstack[PROC_KSTACK_BYTES] __attribute__((aligned(16)));
    bool owns_user_space;
    bool alive;
    uint64_t pid;
    uint64_t ppid;
    uint64_t tgid;
    uint64_t exit_code;
    uint64_t wait_target_pid;
    uint64_t wait_status_addr;
    uint64_t tid_address;
    uint64_t robust_list_head;
    uint64_t robust_list_len;
    uint64_t child_tid_address;
    uint64_t clear_child_tid_uaddr;
    uint64_t clear_child_tid_owner_pid;
    uint64_t thread_flags;
    uint64_t futex_wait_uaddr;
    uint32_t futex_wait_val;
    uint32_t futex_wait_bitset;
    uint64_t futex_wait_result;
    uint8_t futex_waiting;
    uint64_t real_timer_deadline_usec;
    uint64_t real_timer_interval_usec;
    uint8_t real_timer_armed;
    uint64_t signal_pending;
    uint64_t signal_mask;
    uint64_t saved_signal_mask; 
    bool restore_sigmask;
    uint8_t signal_in_handler;
    uint64_t signal_alt_stack_sp;
    uint64_t signal_alt_stack_size;
    uint64_t signal_alt_stack_flags;
    uint64_t signal_frame_addr;
    uint32_t umask;
    struct proc_signal_action signal_actions[PROC_SIGNAL_MAX + 1U];
    uint64_t brk;
    uint64_t mmap_next;
    uint64_t affinity_mask;
    struct proc_mmap_region mmap_regions[PROC_MMAP_MAX];
    uint64_t next_child_pid;
    uint64_t fake_fork_count;
    uint32_t cwd_inode_no;
    int next_fd;
    int test_unlink_removed;
    struct file_descriptor_entry fd_table[PROC_MAX_FD];
    uint64_t last_sys_no;
};

void proc_init_stdio(struct proc *p);

static inline struct file_descriptor_entry *proc_fd_entry(struct proc *p, int fd) {
    if (p == 0 || fd < 0 || fd >= (int)PROC_MAX_FD) {
        return 0;
    }
    return &p->fd_table[fd];
}

static inline struct file *proc_fd_file(struct proc *p, int fd) {
    struct file_descriptor_entry *entry = proc_fd_entry(p, fd);
    return entry != 0 ? entry->file : 0;
}

static inline void proc_reset_file(struct file *file) {
    if (file == 0) {
        return;
    }
    global_file_free(file);
}

static inline void proc_reset_fd_entry(struct file_descriptor_entry *fd) {
    if (fd == 0) {
        return;
    }
    fd->file = 0;
    fd->fd_kind = PROCESS_FD_NONE;
    fd->fd_flags = 0;
    fd->reserved = 0;
}

static inline void proc_init_fd_table(struct proc *p) {
    if (p == 0) {
        return;
    }
    for (uint32_t i = 0; i < PROC_MAX_FD; i++) {
        p->fd_table[i].file = 0;
        p->fd_table[i].fd_kind = PROCESS_FD_NONE;
        p->fd_table[i].fd_flags = 0;
        p->fd_table[i].reserved = 0;
    }
}

static inline void proc_reset_runtime(struct proc *p) {
    if (p == 0) {
        return;
    }

    p->alive = true;
    p->brk = p->space != 0 ? p->space->heap_base : 0;
    p->mmap_next = 0x0000003f10000000ULL;
    for (uint32_t i = 0; i < PROC_MMAP_MAX; i++) {
        p->mmap_regions[i].fd_kind = PROCESS_FD_NONE;
        p->mmap_regions[i].start = 0;
        p->mmap_regions[i].len = 0;
        p->mmap_regions[i].flags = 0;
        p->mmap_regions[i].file_offset = 0;
        p->mmap_regions[i].pte_flags = 0;
        p->mmap_regions[i].mmap_flags = 0;
        p->mmap_regions[i].file = 0;
    }
    p->next_child_pid = 2;
    p->fake_fork_count = 0;
    if (p->cwd_inode_no == 0) {
        p->cwd_inode_no = 2;
    }
    p->next_fd = 3;
    p->test_unlink_removed = 0;
    p->tid_address = 0;
    p->robust_list_head = 0;
    p->robust_list_len = 0;
    p->child_tid_address = 0;
    p->clear_child_tid_uaddr = 0;
    p->clear_child_tid_owner_pid = 0;
    p->thread_flags = 0;
    p->futex_wait_uaddr = 0;
    p->futex_wait_val = 0;
    p->futex_wait_bitset = 0;
    p->futex_wait_result = 0;
    p->futex_waiting = 0;
    p->real_timer_deadline_usec = 0;
    p->real_timer_interval_usec = 0;
    p->real_timer_armed = 0;
    p->signal_pending = 0;
    p->signal_mask = 0;
    p->saved_signal_mask = 0;
    p->restore_sigmask = false;
    p->signal_in_handler = 0;
    p->signal_alt_stack_sp = 0;
    p->signal_alt_stack_size = 0;
    p->signal_alt_stack_flags = 0;
    p->signal_frame_addr = 0;
    p->umask = 0022U;
    for (uint32_t i = 0; i <= PROC_SIGNAL_MAX; i++) {
        p->signal_actions[i].handler = 0;
        p->signal_actions[i].flags = 0;
        p->signal_actions[i].restorer = 0;
        p->signal_actions[i].mask = 0;
    }

    proc_init_fd_table(p);
    proc_init_stdio(p);
}

static inline void proc_init(struct proc *p) {
    if (p == 0) {
        return;
    }

    p->state = PROC_UNUSED;
    p->space = 0;
    p->context.sp = 0;
    p->context.ra = 0;
    p->context.s0 = 0;
    p->context.s1 = 0;
    p->context.s2 = 0;
    p->context.s3 = 0;
    p->context.s4 = 0;
    p->context.s5 = 0;
    p->context.s6 = 0;
    p->context.s7 = 0;
    p->context.s8 = 0;
    p->context.s9 = 0;
    p->context.s10 = 0;
    p->context.s11 = 0;
    p->trap_frame_page = 0;
    p->trap_frame_va = 0;
    p->owns_user_space = false;
    p->alive = false;
    p->pid = 0;
    p->ppid = 0;
    p->exit_code = 0;
    p->wait_target_pid = 0;
    p->wait_status_addr = 0;
    p->tid_address = 0;
    p->robust_list_head = 0;
    p->robust_list_len = 0;
    p->child_tid_address = 0;
    p->clear_child_tid_uaddr = 0;
    p->clear_child_tid_owner_pid = 0;
    p->thread_flags = 0;
    p->futex_wait_uaddr = 0;
    p->futex_wait_val = 0;
    p->futex_wait_bitset = 0;
    p->futex_wait_result = 0;
    p->futex_waiting = 0;
    p->real_timer_deadline_usec = 0;
    p->real_timer_interval_usec = 0;
    p->real_timer_armed = 0;


