static bool parse_header(const uint8_t *image, uint32_t len, struct elf_header *header) {
    if (len < ELF64_EHDR_SIZE) {
        kputs("elf: header too short\n");
        return false;
    }

    if (image[0] != 0x7f || image[1] != 'E' || image[2] != 'L' || image[3] != 'F') {
        // kputs("elf: bad magic\n");
        return false;
    }
    if (image[EI_CLASS] != ELFCLASS64 || image[EI_DATA] != ELFDATA2LSB ||
        image[EI_VERSION] != EV_CURRENT) {
        kputs("elf: unsupported ident\n");
        return false;
    }

    header->type = read_le16(image + 16);
    header->machine = read_le16(image + 18);
    header->entry = read_le64(image + 24);
    header->phoff = read_le64(image + 32);
    header->shoff = read_le64(image + 40);
    header->phentsize = read_le16(image + 54);
    header->phnum = read_le16(image + 56);
    header->shentsize = read_le16(image + 58);
    header->shnum = read_le16(image + 60);

    if (header->type != ET_EXEC && header->type != ET_DYN) {
        kputs("elf: unsupported type=");
        kputhex64(header->type);
        kputs("\n");
        return false;
    }
    if (!machine_matches_kernel(header->machine)) {
        kputs("elf: machine mismatch ");
        kputs(machine_name(header->machine));
        kputs("\n");
        return false;
    }
    if (header->phentsize < ELF64_PHDR_SIZE) {
        kputs("elf: bad phentsize\n");
        return false;
    }
    if (header->shnum != 0 && header->shentsize < ELF64_SHDR_SIZE) {
        kputs("elf: bad shentsize\n");
        return false;
    }
    return true;
}

static bool read_symbol_name(uint32_t inode_no, const uint8_t *strtab,
                             uint32_t name_offset, const char *expect) {
    uint64_t strtab_offset = read_le64(strtab + 24);
    uint64_t strtab_size = read_le64(strtab + 32);
    uint32_t expect_len = 0;
    while (expect[expect_len] != '\0') {
        expect_len++;
    }
    if (expect_len + 1U > sizeof(symbol_name_buffer) ||
        name_offset + (uint64_t)expect_len + 1U > strtab_size) {
        return false;
    }

    uint32_t read_len = 0;
    if (!ext4_read_inode_range(inode_no, strtab_offset + name_offset,
                               symbol_name_buffer, expect_len + 1U,
                               &read_len) ||
        read_len != expect_len + 1U) {
        return false;
    }
    for (uint32_t i = 0; i <= expect_len; i++) {
        if (symbol_name_buffer[i] != (uint8_t)expect[i]) {
            return false;
        }
    }
    return true;
}

static uint64_t find_symbol_addr(uint32_t inode_no, const struct elf_header *header,
                                 const char *name) {
    if (header->shoff == 0 || header->shnum == 0) {
        return 0;
    }

    uint64_t shdr_bytes = (uint64_t)header->shnum * header->shentsize;
    uint32_t read_len = 0;
    if (shdr_bytes == 0 || shdr_bytes > ELF_MAX_SHDR_BYTES ||
        !ext4_read_inode_range(inode_no, header->shoff, shdr_buffer,
                               (uint32_t)shdr_bytes, &read_len) ||
        read_len != shdr_bytes) {
        return 0;
    }

    for (uint16_t i = 0; i < header->shnum; i++) {
        const uint8_t *symtab = shdr_buffer + (uint64_t)i * header->shentsize;
        uint32_t sh_type = read_le32(symtab + 4);
        if (sh_type != SHT_SYMTAB && sh_type != SHT_DYNSYM) {
            continue;
        }

        uint32_t strtab_index = read_le32(symtab + 40);
        uint64_t sym_offset = read_le64(symtab + 24);
        uint64_t sym_size = read_le64(symtab + 32);
        uint64_t sym_entsize = read_le64(symtab + 56);
        if (strtab_index >= header->shnum || sym_entsize < ELF64_SYM_SIZE) {
            continue;
        }

        const uint8_t *strtab =
            shdr_buffer + (uint64_t)strtab_index * header->shentsize;
        for (uint64_t off = 0; off + ELF64_SYM_SIZE <= sym_size;
             off += sym_entsize) {
            uint8_t sym[ELF64_SYM_SIZE];
            if (!ext4_read_inode_range(inode_no, sym_offset + off, sym,
                                       sizeof(sym), &read_len) ||
                read_len != sizeof(sym)) {
                return 0;
            }

            uint32_t name_offset = read_le32(sym);
            uint64_t value = read_le64(sym + 8);
            if (name_offset != 0 && value != 0 &&
                read_symbol_name(inode_no, strtab, name_offset, name)) {
                return value;
            }
        }
    }
    return 0;
}


