typedef uint64_t (*devfs_write_fn)(uint64_t offset, const uint8_t *data, uint64_t len);

struct devfs_node_desc {
    enum devfs_node node;
    const char *name;
    devfs_read_fn read_cb;
    devfs_write_fn write_cb;
};

static char cpu_dma_latency_data[32];
static uint64_t cpu_dma_latency_len;

static uint64_t read_cpu_dma_latency(uint64_t offset, uint8_t *out, uint64_t len) {
    if (!out || offset >= cpu_dma_latency_len) return 0;
    uint64_t readable = cpu_dma_latency_len - offset;
    if (readable > len) readable = len;
    kmemcpy(out, cpu_dma_latency_data + offset, readable);
    return readable;
}

static uint64_t write_cpu_dma_latency(uint64_t offset, const uint8_t *data, uint64_t len) {
    if (!data) return 0;
    uint64_t cap = sizeof(cpu_dma_latency_data) - 1U;
    if (offset > cap) return 0;
    uint64_t writable = (len > cap - offset) ? (cap - offset) : len;
    kmemcpy(cpu_dma_latency_data + offset, data, writable);
    if (cpu_dma_latency_len < offset + writable) {
        cpu_dma_latency_len = offset + writable;
    }
    cpu_dma_latency_data[cpu_dma_latency_len] = '\0';
    return writable;
}

