static int devfs_lookup(struct inode *dir_inode, const char *name, struct dentry **result) {
    struct dentry *parent = dir_inode != 0 && dir_inode->i_sb != 0 ?
                               dir_inode->i_sb->s_root :
                               0;
    struct dentry *existing = vfs_find_child(parent, name);

    if (existing != 0) {
        *result = existing;
        return 0;
    }

    for (size_t i = 0; i < sizeof(devfs_items)/sizeof(devfs_items[0]); i++) {
        if (kstrcmp(devfs_items[i].name, name) == 0) {
            struct inode *inode = (struct inode *)kmalloc(sizeof(struct inode));
            struct dentry *dentry = (struct dentry *)kmalloc(sizeof(struct dentry));
            if (!inode || !dentry) return -ENOMEM;

            kmemset(inode, 0, sizeof(*inode));
            kmemset(dentry, 0, sizeof(*dentry));
            inode->i_ino = (unsigned long)devfs_items[i].node;
            inode->i_mode = S_IFREG | 0666;
            inode->i_private = (void *)&devfs_items[i]; 
            inode->i_fop = &devfs_file_ops;
            inode->i_op = 0;
            inode->i_nlink = 1U;
            inode->i_sb = dir_inode != 0 ? dir_inode->i_sb : 0;

            devfs_copy_name(dentry->d_name, name);
            dentry->d_inode = inode;
            dentry->d_parent = parent;
            if (dentry->d_parent != 0 && vfs_link_child(dentry->d_parent, dentry) != 0) {
                kfree(inode);
                kfree(dentry);
                return -EEXIST;
            }

            *result = dentry;
            return 0;
        }
    }
    return -ENOENT;
}

