static struct proc_pipe *pipe_for_file(struct file *file) {
    uint32_t index;

    if (file == 0) {
        return 0;
    }
    index = (uint32_t)(uintptr_t)file->f_private;
    if (index >= PROC_PIPE_MAX || !proc_pipe_table[index].used) {
        return 0;
    }
    return &proc_pipe_table[index];
}

void pipe_attach_file(struct file *file, bool is_read_end) {
    if (file == 0) {
        return;
    }
    file->f_op = is_read_end ? &pipe_read_ops : &pipe_write_ops;
}

static bool pipe_fd_nonblock_file(struct file *file) {
    return file != 0 && (file->f_flags & OPEN_O_NONBLOCK) != 0;
}

uint64_t pipe_read_to_user_by_file(struct file *file, uint64_t buf, uint64_t len) {
    if (file == 0 || len == 0) {
        return 0;
    }

    while (1) {
        struct proc_pipe *pipe = pipe_for_file(file);
        if (pipe == 0) {
            return (uint64_t)-EBADF;
        }
        if (pipe->len != 0) {
            uint64_t readable = pipe->len;
            if (readable > len) {
                readable = len;
            }
            for (uint64_t i = 0; i < readable; i++) {
                write_user8(buf + i,
                            (uint8_t)pipe->data[(pipe->head + i) % PROC_PIPE_BUF_SIZE]);
            }
            pipe->head = (pipe->head + readable) % PROC_PIPE_BUF_SIZE;
            pipe->len -= readable;
            return readable;
        }
        if (!pipe->write_open) {
            return 0;
        }
        if (pipe_fd_nonblock_file(file)) {
            return (uint64_t)-EAGAIN;
        }
        yield_to_kernel();
        if (proc_current() != 0 && proc_current()->signal_pending != 0) {
            return (uint64_t)-EINTR;
        }

    }
}

uint64_t pipe_write_from_user_by_file(struct file *file, uint64_t buf, uint64_t len) {
    if (file == 0 || len == 0) {
        return 0;
    }

    while (1) {
        struct proc_pipe *pipe = pipe_for_file(file);
        if (pipe == 0) {
            return (uint64_t)-EPIPE;
        }
        if (!pipe->read_open) {
            return (uint64_t)-EPIPE;
        }
        uint64_t writable = PROC_PIPE_BUF_SIZE - pipe->len;
        if (writable != 0) {
            if (writable > len) {
                writable = len;
            }
            for (uint64_t i = 0; i < writable; i++) {
                uint8_t ch = 0;
                if (!read_user8(buf + i, &ch)) {
                    return (uint64_t)-EFAULT;
                }
                pipe->data[(pipe->head + pipe->len + i) % PROC_PIPE_BUF_SIZE] = (char)ch;
            }
            pipe->len += writable;
            return writable;
        }
        if (pipe_fd_nonblock_file(file)) {
            return (uint64_t)-EAGAIN;
        }
        yield_to_kernel();
    }
}

void pipe_attach_file(struct file *file, bool is_read_end);

static long pipe_file_read(struct file *file, void *buf, size_t len) {
    return (long)pipe_read_to_user_by_file(file, (uint64_t)(uintptr_t)buf, (uint64_t)len);
}

static long pipe_file_write(struct file *file, const void *buf, size_t len) {
    return (long)pipe_write_from_user_by_file(file, (uint64_t)(uintptr_t)buf, (uint64_t)len);
}

