static uintptr_t align_down(uintptr_t value, uintptr_t align) {
    return value & ~(align - 1U);
}

static uintptr_t align_up(uintptr_t value, uintptr_t align) {
    return (value + align - 1U) & ~(align - 1U);
}

static uintptr_t trampoline_pa_start(void) {
    return align_down((uintptr_t)riscv_trampoline_start, PAGE_SIZE);
}

static uintptr_t trampoline_pa_end(void) {
    return align_up((uintptr_t)riscv_trampoline_end, PAGE_SIZE);
}

static bool va_in_trampoline_range(uint64_t va) {
    uint64_t trampoline_start = RISCV_TRAMPOLINE_VA;
    uint64_t trampoline_end =
        RISCV_TRAMPOLINE_VA + (uint64_t)(trampoline_pa_end() - trampoline_pa_start());
    return va >= trampoline_start && va < trampoline_end;
}

static bool va_is_trap_frame(uint64_t va) {
    return va >= RISCV_TRAP_FRAME_BASE_VA && va < RISCV_TRAMPOLINE_VA;
}

static bool va_in_vdso_range(uint64_t va) {
    uint64_t vdso_end = USER_VDSO_VA +
                        (uint64_t)(align_up((uintptr_t)riscv_vdso_end, PAGE_SIZE) -
                                   align_down((uintptr_t)riscv_vdso_start, PAGE_SIZE));
    return va >= USER_VDSO_VA && va < vdso_end;
}

static bool va_in_shm_range(uint64_t va) {
    return va >= USER_SHM_BASE && va < USER_SHM_BASE + USER_SHM_SIZE;
}

static bool va_may_share_between_spaces(uint64_t va) {
    return va_in_trampoline_range(va) ||
           va_in_vdso_range(va) ||
           va_in_shm_range(va);
}

static uint16_t vpn_index(uint64_t va, unsigned level) {
    return (uint16_t)((va >> (12U + level * 9U)) & 0x1ffU);
}

static uint64_t *pte_to_table(uint64_t pte) {
    uintptr_t pa = (uintptr_t)((pte >> 10) << 12);
    return (uint64_t *)pa;
}

static void *pte_to_page(uint64_t pte) {
    uintptr_t pa = (uintptr_t)((pte >> 10) << 12);
    return (void *)pa;
}

static uint64_t cstr_len(const char *s) {
    uint64_t len = 0;
    if (s == 0) {
        return 0;
    }
    while (s[len] != '\0') {
        len++;
    }
    return len;
}

