static struct kernel_context scheduler_ctx;

struct kernel_context *riscv_scheduler_context(void) {
    return &scheduler_ctx;
}

static uint64_t proc_user_satp(struct proc *p) {
    uint64_t satp = RISCV_SATP_MODE_SV39 | (p->space->root_table >> 12);
    p->space->satp = satp;
    return satp;
}

static void init_first_user_frame(struct proc *p, struct riscv_trap_frame *frame) {
    for (uint32_t i = 0; i < 32U; i++) {
        frame->regs[i] = 0;
    }

    frame->regs[2] = p->space->stack_top;
    frame->regs[4] = p->space->thread_pointer;
    frame->sepc = p->space->entry;
    frame->sstatus = RISCV_SSTATUS_SPIE | RISCV_SSTATUS_VS_DIRTY |
                     RISCV_SSTATUS_FS_DIRTY | RISCV_SSTATUS_SUM;
}

static struct riscv_trap_frame *proc_trap_frame(struct proc *p) {
    return (struct riscv_trap_frame *)((uintptr_t)p->trap_frame_page +
                                      PAGE_SIZE - sizeof(struct riscv_trap_frame));
}

static void switch_to_user_trampoline(void) {
    struct proc *p = riscv_current_process();
    if (p == 0) {
        return;
    }

    struct riscv_trap_frame *frame = proc_trap_frame(p);
    uint64_t user_satp = proc_user_satp(p);
    (void)riscv_user_resume(user_satp, frame, &p->context,
                            p->trap_frame_va,
                            (uint64_t)(uintptr_t)p->kstack +
                                PROC_KSTACK_BYTES);
}

void fork_ret(void) {
    struct proc *p = riscv_current_process();
    if (p == 0) {
        return;
    }

    riscv_user_trap_reset();
    init_first_user_frame(p, proc_trap_frame(p));
    switch_to_user_trampoline();
}

void scheduler(void) {
    struct proc *table = proc_table_base();
    while (1) {
        int found = 0;
        for (uint32_t i = 0; i < PROC_MAX_PROCS; i++) {
            struct proc *p = &table[i];
            if (p->state != PROC_READY) {
                continue;
            }

            found = 1;
            p->state = PROC_RUNNING;
            riscv_set_current_process(p);

            riscv_resume_kernel_context(&p->context, &scheduler_ctx);

            riscv_set_kernel_trap_vector();
            p = &table[i];
            riscv_set_current_process(0);
            if (p->state == PROC_READY) {
                continue;
            }
            if (p->state == PROC_WAITING || p->state == PROC_ZOMBIE) {
                continue;
            }
            if (p->state != PROC_UNUSED) {
                proc_destroy(p);
            }
        }
        if (!found) {
            return;
        }
    }
}

