#define TIMER_HZ 10000000ULL

static uint64_t tick_count;

static uint64_t read_time(void) {
    uint64_t time;
    asm volatile("csrr %0, time" : "=r"(time));
    return time;
}

static void sbi_set_timer(uint64_t next_time) {
    register uint64_t a0 asm("a0") = next_time;
    register uint64_t a6 asm("a6") = 0;
    register uint64_t a7 asm("a7") = SBI_SET_TIMER_EXT;
    asm volatile("ecall"
                 : "+r"(a0)
                 : "r"(a6), "r"(a7)
                 : "memory");
}

void timer_system_init(void) {
    tick_count = 0;
    asm volatile("csrs sie, %0" ::"r"(SIE_STIE) : "memory");
    sbi_set_timer(read_time() + TIMER_INTERVAL);
}

void timer_handle_interrupt(void) {
    tick_count++;
    sbi_set_timer(read_time() + TIMER_INTERVAL);
}

uint64_t timer_ticks(void) {
    return tick_count;
}

uint64_t timer_usec(void) {
    return read_time() / (TIMER_HZ / 1000000ULL);
}

uint64_t timespec_to_usec(const struct timespec* spec) {
    return spec->tv_sec * 1000000ULL + spec->tv_nsec / 1000ULL;
