static void append_unsigned(char *buf, size_t size, size_t *pos,
                            unsigned long value, unsigned int width, int zero_pad) {
    char tmp[32];
    size_t len = 0;

    do {
        tmp[len++] = (char)('0' + (value % 10UL));
        value /= 10UL;
    } while (value != 0UL && len < sizeof(tmp));

    while (len < width) {
        append_char(buf, size, pos, zero_pad != 0 ? '0' : ' ');
        width--;
