size_t ksnprintf(char *buf, size_t size, const char *fmt, ...) {
    va_list ap;
    size_t pos = 0;

    if (buf == 0 || size == 0 || fmt == 0) {
        return 0;
    }

    va_start(ap, fmt);
    for (size_t i = 0; fmt[i] != '\0'; i++) {
        if (fmt[i] != '%') {
            append_char(buf, size, &pos, fmt[i]);
            continue;
        }

        i++;
        if (fmt[i] == '0') {
            unsigned int width = 0;
            int zero_pad = 1;

            i++;
            while (fmt[i] >= '0' && fmt[i] <= '9') {
                width = width * 10U + (unsigned int)(fmt[i] - '0');
                i++;
            }
            if (fmt[i] == 'l' && fmt[i + 1] == 'u') {
                unsigned long value = va_arg(ap, unsigned long);
                append_unsigned(buf, size, &pos, value, width, zero_pad);
                i++;
                continue;
            }
        } else if (fmt[i] == 'l' && fmt[i + 1] == 'u') {
            unsigned long value = va_arg(ap, unsigned long);
            append_unsigned(buf, size, &pos, value, 0U, 0);
            i++;
            continue;
        } else if (fmt[i] == 's') {
            const char *s = va_arg(ap, const char *);
            if (s == 0) {
                s = "(null)";
            }
            while (*s != '\0') {
                append_char(buf, size, &pos, *s++);
            }
            continue;
        } else if (fmt[i] == 'c') {
            char c = (char)va_arg(ap, int); 
            append_char(buf, size, &pos, c);
            continue;
        } else if (fmt[i] == 'd') {
            int val = va_arg(ap, int);
            // 如果你实现了 append_signed，用它来打印负数/正数
            // 如果没有，可以先临时用 append_unsigned（如果不考虑负数的话）
            unsigned int uval = (val < 0) ? -val : val;
            if (val < 0) {
                append_char(buf, size, &pos, '-');
            }
            append_unsigned(buf, size, &pos, uval, 0U, 0);
            continue;
        } else if (fmt[i] == '%') {
            append_char(buf, size, &pos, '%');
            continue;
        }

        if (fmt[i] != '\0') {
            append_char(buf, size, &pos, fmt[i]);
        }
    }
    va_end(ap);

    if (pos < size) {
        buf[pos] = '\0';
    } else {
        buf[size - 1U] = '\0';
    }
    return pos;
}

static uint64_t sys_clone(struct riscv_trap_frame *frame) {
