    uint64_t flags = frame->regs[10];
    struct proc *child = proc_fork(current_process, flags);
    if (child == 0) {
        return (uint64_t)-ENOMEM;
    }

    struct riscv_trap_frame *child_frame =
        (struct riscv_trap_frame *)((uintptr_t)child->trap_frame_page +
                                    PAGE_SIZE - sizeof(*child_frame));
    copy_bytes(child_frame, frame, sizeof(*child_frame));
    init_cloned_trap_metadata(child, child_frame);
    child_frame->regs[10] = 0;
    if (frame->regs[11] != 0) {
        child_frame->regs[2] = frame->regs[11];
    }
    uint64_t parent_tid = frame->regs[12];
    uint64_t tls = frame->regs[13];
    uint64_t child_tid = frame->regs[14];

    child->thread_flags = flags;
    if ((flags & CLONE_VM) != 0) {
        child->tgid = current_process->tgid;
    } else {
        child->tgid = child->pid;
    }    
    if ((flags & CLONE_SETTLS) != 0) {
        child->space->thread_pointer = tls;
        child_frame->regs[4] = tls;
    }
    if ((flags & CLONE_CHILD_SETTID) != 0 && child_tid != 0) {
        write_user32_in_space(child->space, child_tid, (uint32_t)child->pid);
    }
    if ((flags & CLONE_PARENT_SETTID) != 0 && parent_tid != 0) {
        write_user32(parent_tid, (uint32_t)child->pid);
    }
    if ((flags & CLONE_CHILD_CLEARTID) != 0 && child_tid != 0) {
        child->child_tid_address = child_tid;
        child->clear_child_tid_uaddr = child_tid;
        child->clear_child_tid_owner_pid =
            (flags & CLONE_VM) != 0 ? current_process->pid : child->pid;
    }

    // kputs("\n[SYS_CLONE] Parent PID: "); kputhex64(current_process->pid);
