static uint64_t sys_execve(struct riscv_trap_frame *frame, uint64_t name,
                           uint64_t argv, uint64_t envp) {
    if (current_process == 0 || frame == 0) {
        return (uint64_t)-ENOMEM;
    }

    char path[EXEC_PATH_MAX];
    if (!copy_user_cstr(name, path, sizeof(path))) {
        return (uint64_t)-EFAULT;
    }

    struct exec_arg_block *args = &exec_arg_scratch;
    struct exec_arg_block *envs = &exec_env_scratch;

    int res = collect_exec_args(argv, path, args);
    if (res != 0) {
        return (uint64_t)res;
    }

    res = collect_exec_envs(envp, envs);
    if (res != 0) {
        return (uint64_t)res;
    }
    // bool is_shell = kstrcmp(args->value[1], "lat_proc") == 0 && kstrcmp(args->value[2], "-P") == 0
    //             && kstrcmp(args->value[3], "1") == 0 && kstrcmp(args->value[4], "shell") == 0;
    // if (kstrcmp(args->value[0], "./lmbench_all") == 0 && !is_shell) {
    //     return 0;
    // }
    uint32_t inode_no = 0;


    if (!ext4_lookup_path(current_process->cwd_inode_no, path, &inode_no)) {
        if (path_is_busybox_applet(path) && ext4_get_busybox_inode_no() != 0) {
            inode_no = ext4_get_busybox_inode_no();
        } else {
            return (uint64_t)-ENOENT;
        }
    }

    char interpreter[EXEC_PATH_MAX] = {0};
    char interpreter_arg[EXEC_ARG_STR_MAX] = {0};
    bool has_interpreter_arg = false;

    int shebang_result = parse_shebang(inode_no, interpreter, interpreter_arg, &has_interpreter_arg);
    if (shebang_result < 0) {
        return (uint64_t)shebang_result;
    }

    if (shebang_result > 0) {
        res = rewrite_shebang_args(args, interpreter, interpreter_arg, has_interpreter_arg, path);
        if (res != 0) {
            return (uint64_t)res;
        }
        inode_no = ext4_get_busybox_inode_no();
    } else if (cstr_has_suffix(path, ".sh")) {
        uint32_t sh_inode = ext4_get_busybox_inode_no();
        if (!lookup_busybox_sh(&sh_inode)) {
            return (uint64_t)-ENOENT;
        }

        res = rewrite_shebang_args(args, "sh", "", false, path);
        if (res != 0) {
            return (uint64_t)res;
        }
        inode_no = sh_inode;
    }

    struct user_space *new_space = &exec_new_space_scratch;
    if (!elf_load_user_space(inode_no, new_space)) {
        return (uint64_t)-8;
    }

    uint64_t new_sp = 0;
    res = build_exec_stack(new_space, args, envs, &new_sp);
    if (res != 0) {
        user_space_destroy(new_space);
        return (uint64_t)res;
    }

    struct user_space *old_space = current_process->space;
    struct user_space *new_copy = user_space_alloc_copy(new_space);
    if (new_copy == 0) {
        user_space_destroy(new_space);
        return (uint64_t)-ENOMEM;
    }
    if (!user_space_map_supervisor_page(new_copy, current_process->trap_frame_va,
                                        current_process->trap_frame_page)) {
        kputs("trap frame map failed in sys_execve");
        user_space_destroy(new_copy);
        user_space_destroy(new_space);
        return (uint64_t)-ENOMEM;
    }

    current_process->space = new_copy;
    current_process->owns_user_space = true;
    current_process->brk = current_process->space->heap_base;
    current_process->mmap_next = USER_MMAP_BASE;
    clear_all_mmap_regions(current_process);
    proc_reset_signal_handlers(current_process);

    for (uint64_t fd = 0; fd < PROC_MAX_FD; fd++) {
        struct file_descriptor_entry* f_desc = &current_process->fd_table[fd];
        struct file *file = f_desc->file;
        if (file != 0 && (f_desc->fd_flags & FD_CLOEXEC) != 0) {
            close_fd(fd);
        }
    }

    if (old_space != 0) {
        user_space_release(old_space);
    }

    for (uint32_t i = 0; i < 32U; i++) {
        frame->regs[i] = 0;
    }
    frame->regs[2] = new_sp;
    frame->regs[4] = current_process->space->thread_pointer;
    frame->sepc = new_space->entry;
    frame->user_satp = current_process->space->satp;
    current_process->last_sys_no = SYS_EXECVE;

    return 0;
}

