static bool write_ext4_dirent64(uint64_t entry_index, uint32_t inode_no,
                                uint8_t file_type, const char *name,
                                uint8_t name_len, void *ctx_ptr) {
    struct getdents64_ctx *ctx = (struct getdents64_ctx *)ctx_ptr;
    uint64_t reclen = align_up_u64(19U + (uint64_t)name_len + 1U, 8U);
    uint8_t type = file_type == 2U ? 4U : 8U;

    if (ctx->written + reclen > ctx->len) {
