    zero_user_bytes(ctx->buf + ctx->written, reclen);
    write_user64(ctx->buf + ctx->written, inode_no);
    write_user64(ctx->buf + ctx->written + 8U, reclen);
    write_user16(ctx->buf + ctx->written + 16U, (uint16_t)reclen);
    write_user8(ctx->buf + ctx->written + 18U, type);
    copy_to_user(ctx->buf + ctx->written + 19U, name, (uint64_t)name_len);
    ctx->written += reclen;
    ctx->entries = entry_index + 1U;
    (void)entry_index;
    return true;
}

static int64_t ext4_getdents(uint32_t inode_no, uint64_t *off, uint64_t buf,
                             uint64_t len) {
    struct getdents64_ctx ctx;

    if (off == 0) {
        return (int64_t)-EINVAL;
    }
    if (!ext4_inode_is_dir(inode_no)) {
        return (int64_t)-ENOTDIR;
    }
    if (len < 32U) {
        return (int64_t)-EINVAL;
    }

    ctx.buf = buf;
    ctx.len = len;
    ctx.written = 0;
    ctx.entries = 0;
    if (!ext4_iterate_dirents(inode_no, *off, write_ext4_dirent64, &ctx) &&
        ctx.written == 0) {
        return (int64_t)-EFAULT;
    }
    *off += ctx.entries;
    return (int64_t)ctx.written;
}

