static uint64_t sys_socket(uint64_t domain, uint64_t type, uint64_t protocol) {
    if (domain != AF_INET) {
        return (uint64_t)-EAFNOSUPPORT;
    }
    return (uint64_t)alloc_socket_fd(type, protocol);
}

static uint64_t sys_bind(uint64_t fd) {
    return fd_is_socket(fd) ? 0 : (uint64_t)-ENOTSOCK;
}

static uint64_t sys_listen(uint64_t fd) {
    return fd_is_socket(fd) ? 0 : (uint64_t)-ENOTSOCK;
}

static uint64_t sys_connect(uint64_t fd) {
    return fd_is_socket(fd) ? 0 : (uint64_t)-ENOTSOCK;
}

static uint64_t sys_getsockname(uint64_t fd, uint64_t addr,
                                uint64_t addrlen_addr) {
    if (!fd_is_socket(fd)) {
        return (uint64_t)-ENOTSOCK;
    }
    write_sockaddr_in(addr, addrlen_addr);
    return 0;
}

static uint64_t sys_setsockopt(uint64_t fd) {
    return fd_is_socket(fd) ? 0 : (uint64_t)-ENOTSOCK;
}

static uint64_t sys_getsockopt(uint64_t fd, uint64_t optval,
                               uint64_t optlen_addr) {
    if (!fd_is_socket(fd)) {
        return (uint64_t)-ENOTSOCK;
    }
    uint32_t optlen = 0;
    if (optlen_addr != 0 && !read_user32(optlen_addr, &optlen)) {
        return (uint64_t)-EFAULT;
    }
    if (optval != 0 && optlen != 0) {
        zero_user_bytes(optval, optlen < 4U ? optlen : 4U);
    }
    if (optlen_addr != 0) {
        write_user32(optlen_addr, 4U);
    }
    return 0;
}

static uint64_t sys_accept(uint64_t fd, uint64_t addr, uint64_t addrlen_addr,
                           uint64_t flags) {
    if (!fd_is_socket(fd)) {
        return (uint64_t)-ENOTSOCK;
    }
    int newfd = alloc_socket_fd(SOCK_STREAM |
                                    (flags & (SOCK_CLOEXEC | SOCK_NONBLOCK)),
                                0);
    if (newfd < 0) {
        return (uint64_t)newfd;
    }
    write_sockaddr_in(addr, addrlen_addr);
    return (uint64_t)newfd;
}

static uint64_t sys_sendto(uint64_t fd, uint64_t buf, uint64_t len) {
    if (!fd_is_socket(fd)) {
        return (uint64_t)-ENOTSOCK;
    }
    if (len != 0) {
        if (!read_user8(buf, &socket_packet)) {
            return (uint64_t)-EFAULT;
        }
        socket_packet_len = 1;
    }
    return len;
}

static uint64_t sys_recvfrom(uint64_t fd, uint64_t buf, uint64_t len,
                             uint64_t addr, uint64_t addrlen_addr) {
    if (!fd_is_socket(fd)) {
        return (uint64_t)-ENOTSOCK;
    }
    if (len == 0) {
        return 0;
    }
    if (socket_packet_len == 0) {
        struct file_descriptor_entry *f_desc = fd_file_desc(fd);
struct file *file = f_desc->file;
        if (file != 0 && (file->f_flags & OPEN_O_NONBLOCK) != 0) {
            return (uint64_t)-EAGAIN;
        }
        socket_packet = 0;
        socket_packet_len = 1;
    }
    write_user8(buf, socket_packet);
    socket_packet_len = 0;
    write_sockaddr_in(addr, addrlen_addr);
    return 1;
}

static uint64_t sys_sendmsg(uint64_t fd, uint64_t msg_addr) {
    if (!fd_is_socket(fd)) {
        return (uint64_t)-ENOTSOCK;
    }
    uint64_t iov = 0;
    uint64_t iovcnt = 0;
    if (!read_user64(msg_addr + 16U, &iov) ||
        !read_user64(msg_addr + 24U, &iovcnt)) {
        return (uint64_t)-EFAULT;
    }
    uint64_t total = 0;
    for (uint64_t i = 0; i < iovcnt; i++) {
        uint64_t base = 0;
        uint64_t len = 0;
        if (!read_user64(iov + i * 16U, &base) ||
            !read_user64(iov + i * 16U + 8U, &len)) {
            return total != 0 ? total : (uint64_t)-EFAULT;
        }
        if (len != 0 && socket_packet_len == 0) {
            if (!read_user8(base, &socket_packet)) {
                return total != 0 ? total : (uint64_t)-EFAULT;
            }
            socket_packet_len = 1;
        }
        total += len;
    }
    return total;
}

static uint64_t sys_recvmsg(uint64_t fd, uint64_t msg_addr) {
    if (!fd_is_socket(fd)) {
        return (uint64_t)-ENOTSOCK;
    }
    uint64_t iov = 0;
    uint64_t iovcnt = 0;
    if (!read_user64(msg_addr + 16U, &iov) ||
        !read_user64(msg_addr + 24U, &iovcnt)) {
        return (uint64_t)-EFAULT;
    }
    if (iovcnt == 0) {
        return 0;
    }
    uint64_t base = 0;
    uint64_t len = 0;
    if (!read_user64(iov, &base) || !read_user64(iov + 8U, &len)) {
        return (uint64_t)-EFAULT;
    }
    if (len == 0) {
        return 0;
    }
    if (socket_packet_len == 0) {
        socket_packet = 0;
        socket_packet_len = 1;
    }
    write_user8(base, socket_packet);
    socket_packet_len = 0;
    return 1;
}

static uint64_t sys_futex(uint64_t uaddr, uint64_t op, uint64_t val,
                          uint64_t arg3, uint64_t uaddr2, uint64_t val3) {
    uint64_t cmd = op & FUTEX_CMD_MASK;
    if (cmd == FUTEX_WAKE || cmd == FUTEX_WAKE_BITSET) {
        uint32_t bitset = cmd == FUTEX_WAKE_BITSET ?
                              (uint32_t)val3 :
                              FUTEX_BITSET_MATCH_ANY;
        if (bitset == 0) {
            return (uint64_t)-EINVAL;
        }
        return futex_wake_waiters(uaddr, val, bitset, 0);
    }
    if (cmd == FUTEX_WAIT || cmd == FUTEX_WAIT_BITSET) {
        uint32_t current = 0;
        uint32_t bitset = cmd == FUTEX_WAIT_BITSET ?
                              (uint32_t)val3 :
                              FUTEX_BITSET_MATCH_ANY;
        if (bitset == 0) {
            return (uint64_t)-EINVAL;
        }
        if (!read_user32(uaddr, &current)) {
            return (uint64_t)-EFAULT;
        }
        if (current != (uint32_t)val) {
            return (uint64_t)-EAGAIN;
        }
        if (current_process == 0) {
            return (uint64_t)-EAGAIN;
        }
        current_process->futex_wait_uaddr = uaddr;
        current_process->futex_wait_val = (uint32_t)val;
        current_process->futex_wait_bitset = bitset;
        current_process->futex_wait_result = 0;
        current_process->futex_waiting = 1;
        current_process->state = PROC_WAITING;
        return_to_scheduler(0);
        return current_process != 0 ? current_process->futex_wait_result :
                                      (uint64_t)-EINTR;
    }
    if (cmd == FUTEX_REQUEUE || cmd == FUTEX_CMP_REQUEUE ||
        cmd == FUTEX_CMP_REQUEUE_PI) {
        if (cmd == FUTEX_CMP_REQUEUE || cmd == FUTEX_CMP_REQUEUE_PI) {
            uint32_t current = 0;
            if (!read_user32(uaddr, &current)) {
                return (uint64_t)-EFAULT;
            }
            if (current != (uint32_t)val3) {
                return (uint64_t)-EAGAIN;
            }
        }
        uint64_t woken =
            futex_wake_waiters(uaddr, val, FUTEX_BITSET_MATCH_ANY, 0);
        uint64_t requeued = uaddr2 != 0 ?
                                futex_requeue_waiters(uaddr, uaddr2, arg3) :
                                0;
        return woken + requeued;
    }
    if (cmd == FUTEX_WAKE_OP) {
        uint64_t woken =
            futex_wake_waiters(uaddr, val, FUTEX_BITSET_MATCH_ANY, 0);
        if (uaddr2 != 0) {
            woken += futex_wake_waiters(uaddr2, arg3,
                                        FUTEX_BITSET_MATCH_ANY, 0);
        }
        return woken;
    }
    if (cmd == FUTEX_LOCK_PI || cmd == FUTEX_LOCK_PI2 ||
        cmd == FUTEX_UNLOCK_PI || cmd == FUTEX_TRYLOCK_PI ||
        cmd == FUTEX_WAIT_REQUEUE_PI) {
        return 0;
    }
    return 0;
}

static int collect_exec_args(uint64_t argv, const char *path,
                             struct exec_arg_block *args) {
    if (args == 0) {
        return -EFAULT;
    }

    clear_exec_arg_block(args);
    uint64_t total = 0;

    if (argv == 0) {
        if (!copy_user_cstr((uint64_t)path, args->value[0], EXEC_ARG_STR_MAX)) {
            return -EFAULT;
        }
        args->len[0] = cstr_len(args->value[0]) + 1U;
        args->argc = 1;
        return 0;
    }

    for (uint64_t i = 0; i < EXEC_ARG_MAX; i++) {
        uint64_t argp = 0;
        if (!read_user64(argv + i * sizeof(uint64_t), &argp)) {
            return -EFAULT;
        }
        if (argp == 0) {
            return 0;
        }
        if (!copy_user_cstr(argp, args->value[i], EXEC_ARG_STR_MAX)) {
            return -EFAULT;
        }

        args->len[i] = cstr_len(args->value[i]) + 1U;
        total += args->len[i];
        if (total > EXEC_STACK_ARG_BYTES_MAX) {
            return -E2BIG;
        }
        args->argc++;
    }

    uint64_t extra_arg = 0;
    if (!read_user64(argv + EXEC_ARG_MAX * sizeof(uint64_t), &extra_arg)) {
        return -EFAULT;
    }
    if (extra_arg != 0) {
        return -E2BIG;
    }
    return 0;
}

