static uint64_t sys_rt_sigreturn(struct riscv_trap_frame *frame) {
    if (current_process == 0 || frame == 0 || !current_process->signal_in_handler) {
        return (uint64_t)-EINVAL;
    }

    uint64_t frame_addr = current_process->signal_frame_addr != 0 ?
                              current_process->signal_frame_addr :
                              frame->regs[2];
    struct signal_user_frame sigframe;
    if (!copy_from_user_bytes(frame_addr, &sigframe, sizeof(sigframe)) ||
        sigframe.magic != SIGNAL_FRAME_MAGIC) {
        uint64_t encoded = (uint64_t)(SIGKILL & 0x7f);
        proc_exit(current_process, encoded);
        return 0;
    }

    copy_bytes(frame, &sigframe.frame, sizeof(*frame));
    current_process->signal_mask = signal_user_mask(sigframe.old_mask);
    current_process->signal_in_handler = 0;
    current_process->signal_frame_addr = 0;
    return frame->regs[10];
}

static uint64_t sys_rt_sigaction(uint64_t signo, uint64_t act_addr,
                                 uint64_t old_addr, uint64_t sigset_size) {
    if (!signal_is_valid(signo) || signo == SIGKILL || signo == SIGSTOP) {
        return (uint64_t)-EINVAL;
    }
    if (sigset_size < sizeof(uint64_t) || current_process == 0) {
        return (uint64_t)-EINVAL;
    }

    struct proc_signal_action *action = &current_process->signal_actions[signo];
    if (old_addr != 0) {
        struct user_sigaction old_action;
        old_action.handler = action->handler;
        old_action.flags = action->flags;
        old_action.restorer = vdso_rt_sigreturn_addr();
        old_action.mask = action->mask;
        if (!copy_to_user_bytes_checked(old_addr, &old_action, sizeof(old_action))) {
            return (uint64_t)-EFAULT;
        }
    }
    if (act_addr != 0) {
        struct user_sigaction new_action;
        if (!copy_from_user_bytes(act_addr, &new_action, sizeof(new_action))) {
            return (uint64_t)-EFAULT;
        }
        action->handler = new_action.handler;
        action->flags = new_action.flags;
        action->restorer = vdso_rt_sigreturn_addr();
        action->mask = signal_user_mask(new_action.mask);
    }
    return 0;
}

static uint64_t sys_rt_sigprocmask(uint64_t how, uint64_t set_addr,
                                   uint64_t old_addr, uint64_t sigset_size) {
    if (current_process == 0 || sigset_size < sizeof(uint64_t)) {
        return (uint64_t)-EINVAL;
    }
    if (old_addr != 0 &&
        !copy_to_user_bytes_checked(old_addr, &current_process->signal_mask,
                                    sizeof(current_process->signal_mask))) {
        return (uint64_t)-EFAULT;
    }
    if (set_addr == 0) {
        return 0;
    }

    uint64_t set = 0;
    if (!read_user64(set_addr, &set)) {
        return (uint64_t)-EFAULT;
    }
    set = signal_user_mask(set);
    if (how == SIG_BLOCK) {
        current_process->signal_mask = signal_user_mask(current_process->signal_mask | set);
    } else if (how == SIG_UNBLOCK) {
        current_process->signal_mask = signal_user_mask(current_process->signal_mask & ~set);
    } else if (how == SIG_SETMASK) {
        current_process->signal_mask = set;
    } else {
        return (uint64_t)-EINVAL;
    }
    return 0;
}

static uint64_t sys_rt_sigtimedwait(uint64_t set_addr, uint64_t info_addr,
                                    uint64_t timeout_addr, uint64_t sigset_size) {
    if (current_process == 0 || set_addr == 0 || sigset_size < sizeof(uint64_t)) {
        return (uint64_t)-EINVAL;
    }

    uint64_t set = 0;
    if (!read_user64(set_addr, &set)) {
        return (uint64_t)-EFAULT;
    }
    set = signal_user_mask(set);

    uint64_t deadline_usec = UINT64_MAX;
    if (timeout_addr != 0) {
        struct timespec timeout;
        if (!read_user_timespec(timeout_addr, &timeout)) {
            return (uint64_t)-EFAULT;
        }
        if (!timespec_is_valid(&timeout)) {
            return (uint64_t)-EINVAL;
        }
        deadline_usec = timer_usec() + timespec_to_usec(&timeout);
    }

    for (;;) {
        uint64_t signo = proc_next_signal_in_mask(current_process, set);
        if (signo != 0) {
            current_process->signal_pending &= ~signal_bit(signo);
            if (!write_signal_info(info_addr, signo)) {
                return (uint64_t)-EFAULT;
            }
            return signo;
        }

        if (timeout_addr != 0 && timer_usec() >= deadline_usec) {
            return (uint64_t)-EAGAIN;
        }
        if (proc_next_signal(current_process) != 0) {
            return (uint64_t)-EINTR;
        }
        if (proc_check_real_timer(current_process)) {
            return (uint64_t)-EINTR;
        }
        yield_to_kernel();
    }
}

static uint64_t sys_sigaltstack(uint64_t new_addr, uint64_t old_addr) {
    if (current_process == 0) {
        return (uint64_t)-EINVAL;
    }
    if (old_addr != 0) {
        struct user_stack_t old_stack;
        old_stack.sp = current_process->signal_alt_stack_sp;
        old_stack.flags = current_process->signal_alt_stack_flags;
        old_stack.size = current_process->signal_alt_stack_size;
        if (!copy_to_user_bytes_checked(old_addr, &old_stack, sizeof(old_stack))) {
            return (uint64_t)-EFAULT;
        }
    }
    if (new_addr != 0) {
        struct user_stack_t new_stack;
        if (!copy_from_user_bytes(new_addr, &new_stack, sizeof(new_stack))) {
            return (uint64_t)-EFAULT;
        }
        current_process->signal_alt_stack_sp = new_stack.sp;
        current_process->signal_alt_stack_size = new_stack.size;
        current_process->signal_alt_stack_flags = new_stack.flags;
    }
    return 0;
}

static uint64_t sys_shmget(uint64_t key, uint64_t size, uint64_t flags) {
    int existing = find_shm_by_key(key);
    if (existing >= 0) {
        if ((flags & IPC_CREAT) != 0 && (flags & IPC_EXCL) != 0) {
            return (uint64_t)-EEXIST;
        }
        return (uint64_t)(existing + 1);
    }
    if (key != 0 && (flags & IPC_CREAT) == 0) {
        return (uint64_t)-ENOENT;
    }

    int index = find_free_shm_segment();
    if (index < 0) {
        return (uint64_t)-ENOSPC;
    }
    if (size == 0) {
        size = PAGE_SIZE;
    }
    if (size > SHM_SEGMENT_BYTES) {
        size = SHM_SEGMENT_BYTES;
    }

    struct sysv_shm_segment *segment = &shm_segments[index];
    clear_shm_segment(segment);
    segment->used = 1;
    segment->key = key;
    segment->size = align_up_u64(size, PAGE_SIZE);
    return (uint64_t)(index + 1);
}

static uint64_t sys_shmat(uint64_t shmid, uint64_t shmaddr, uint64_t shmflg) {
    (void)shmaddr;
    int index = shm_id_to_index(shmid);
    if (index < 0 || !shm_segments[index].used || current_process == 0) {
        return (uint64_t)-EINVAL;
    }

    struct sysv_shm_segment *segment = &shm_segments[index];
    uint64_t addr = shm_segment_addr((uint32_t)index);
    uint64_t page_count = segment->size / PAGE_SIZE;
    if (page_count == 0) {
        page_count = 1;
    }
    if (page_count > SHM_PAGES_MAX) {
        page_count = SHM_PAGES_MAX;
    }

    uint64_t pte_flags = RISCV_PTE_R;
    if ((shmflg & 010000ULL) == 0) {
        pte_flags |= RISCV_PTE_W;
    }
    for (uint32_t i = 0; i < page_count; i++) {
        if (segment->pages[i] == 0) {
            segment->pages[i] = page_alloc();
            if (segment->pages[i] == 0) {
                return (uint64_t)-ENOMEM;
            }
            zero_page_bytes(segment->pages[i]);
        }
        if (!map_user_existing_page(current_process->space,
                                    addr + (uint64_t)i * PAGE_SIZE,
                                    segment->pages[i], pte_flags)) {
            return (uint64_t)-ENOMEM;
        }
    }
    if (add_mmap_region(current_process, addr, page_count * PAGE_SIZE,
                        MMAP_PROT_READ | MMAP_PROT_WRITE, 0, 0,
                        MMAP_MAP_ANONYMOUS)) {
        segment->attach_count++;
    }
    return addr;
}

static uint64_t sys_shmdt(uint64_t shmaddr) {
    if (shmaddr >= USER_SHM_BASE) {
        uint64_t index = (shmaddr - USER_SHM_BASE) / SHM_SEGMENT_BYTES;
        if (index < SHM_SEGMENT_MAX && shm_segments[index].attach_count != 0) {
            shm_segments[index].attach_count--;
            if (shm_segments[index].marked_destroy &&
                shm_segments[index].attach_count == 0) {
                shm_segments[index].used = 0;
            }
        }
    }
    return 0;
}

static uint64_t sys_shmctl(uint64_t shmid, uint64_t cmd, uint64_t buf) {
    int index = shm_id_to_index(shmid);
    if (index < 0 || !shm_segments[index].used) {
        return (uint64_t)-EINVAL;
    }
    struct sysv_shm_segment *segment = &shm_segments[index];
    if (cmd == IPC_RMID) {
        segment->marked_destroy = 1;
        if (segment->attach_count == 0) {
            segment->used = 0;
        }
        return 0;
    }
    if (cmd == IPC_STAT || cmd == IPC_INFO ||
        cmd == SHM_STAT || cmd == SHM_INFO || cmd == IPC_SET) {
        if (buf != 0) {
            zero_user_bytes(buf, 128U);
            write_user64(buf + 48U, segment->size);
        }
        return cmd == SHM_STAT ? shmid : 0;
    }
    return 0;
}

