bool ext4_read_inode_range(uint32_t inode_no, uint64_t offset, uint8_t *out,
                           uint32_t len, uint32_t *read_len) {
    if (!read_inode(inode_no, inode_buffer)) {
        return false;
    }

    uint32_t flags = read_le32(inode_buffer + 32);
    if ((flags & EXT4_EXTENTS_FL) == 0) {
        return false;
    }

    uint64_t file_size = read_le64_split(inode_buffer + 4, inode_buffer + 108);
    const uint8_t *extent_header = inode_buffer + 40;
    if (read_le16(extent_header) != EXT4_EXTENT_MAGIC) {
        return false;
    }

    if (offset >= file_size) {
        *read_len = 0;
        return true;
    }
    if ((uint64_t)len > file_size - offset) {
        len = (uint32_t)(file_size - offset);
    }

    zero_bytes(out, len);
    uint32_t copied = 0;
    uint16_t depth = read_le16(extent_header + 6);
    if (depth == 0) {
        if (!read_extent_leaf_range(extent_header, offset, out, len, &copied)) {
            return false;
        }
        *read_len = len;
        return true;
    }
    if (depth == 1) {
        uint16_t entries = read_le16(extent_header + 2);
        for (uint16_t i = 0; i < entries; i++) {
            const uint8_t *index = extent_header + 12U + (uint32_t)i * 12U;
            uint64_t leaf = ((uint64_t)read_le16(index + 8) << 32) | read_le32(index + 4);
            if (!read_block(leaf, extent_buffer) ||
                read_le16(extent_buffer) != EXT4_EXTENT_MAGIC ||
                !read_extent_leaf_range(extent_buffer, offset, out, len, &copied)) {
                return false;
            }
        }
        *read_len = len;
        return true;
    }
    return false;
}


static void run_found_test_scripts(void) {
    if (busybox_inode_no == 0) {
        kputs("ext4: busybox not found\n");
        return;
    }

    for (unsigned i = 0; i < test_script_count; i++) {
        const struct test_script *script = &test_scripts[i];
        const char *argv[] = { "sh", script->name };
        uint32_t shell_inode_no = busybox_inode_no;
        (void)ext4_lookup_path(script->parent_inode_no, "busybox",
                               &shell_inode_no);
        user_set_cwd_inode(script->parent_inode_no);
        (void)elf_run_inode_argv(shell_inode_no, 2, argv);
        scheduler();
    }
    user_set_cwd_inode(EXT4_ROOT_INO);
}

static bool scan_root_dir(void) {
    if (!read_inode(EXT4_ROOT_INO, inode_buffer)) {
        return false;
    }

    test_script_count = 0;
    cached_dirent_count = 0;
    busybox_inode_no = 0;
    if (!visit_dir_inode(EXT4_ROOT_INO, 0, recursive_scan_cb)) {
        return false;
    }
    sort_test_scripts();
    run_found_test_scripts();
    return true;
}

bool ext4_run_test_scripts(void) {
    return scan_root_dir();
}

bool ext4_probe(void) {
    if (!virtio_blk_read_sector(EXT4_SUPERBLOCK_SECTOR, superblock_sector)) {
        return false;
    }

    uint16_t magic = read_le16(superblock_sector + EXT4_SUPERBLOCK_MAGIC_OFFSET);
    if (magic != EXT4_MAGIC) {
        return false;
    }

    uint32_t log_block_size =
        read_le32(superblock_sector + EXT4_SUPERBLOCK_LOG_BLOCK_SIZE_OFFSET);
    block_size = 1024U << log_block_size;
    blocks_per_group = read_le32(superblock_sector + EXT4_SUPERBLOCK_BLOCKS_PER_GROUP_OFFSET);
    inodes_per_group = read_le32(superblock_sector + EXT4_SUPERBLOCK_INODES_PER_GROUP_OFFSET);
    inode_size = read_le16(superblock_sector + EXT4_SUPERBLOCK_INODE_SIZE_OFFSET);
    desc_size = read_le16(superblock_sector + EXT4_SUPERBLOCK_DESC_SIZE_OFFSET);
    if (desc_size < 32U) {
        desc_size = 32U;
    }

    if (blocks_per_group == 0 || inodes_per_group == 0 ||
        block_size > EXT4_MAX_BLOCK_SIZE) {
        return false;
    }

    return true;
