void proc_system_init(void) {
    next_pid = 1;

    for (uint32_t i = 0; i < PROC_MAX_PROCS; i++) {
        proc_init(&proc_table[i]);
    }
    for (uint32_t i = 0; i < PROC_PIPE_MAX; i++) {
        proc_pipe_table[i].used = 0;
        proc_pipe_table[i].read_open = 0;
        proc_pipe_table[i].write_open = 0;
        proc_pipe_table[i].head = 0;
        proc_pipe_table[i].len = 0;
        for (uint32_t j = 0; j < PROC_PIPE_BUF_SIZE; j++) {
            proc_pipe_table[i].data[j] = '\0';
        }
    }
    for (uint32_t i = 0; i < PROC_MEM_FILE_MAX; i++) {
        proc_mem_file_table[i].used = 0;
        proc_mem_file_table[i].len = 0;
        for (uint32_t j = 0; j < PROC_MEM_FILE_PATH_MAX; j++) {
            proc_mem_file_table[i].path[j] = '\0';
        }
        for (uint32_t j = 0; j < PROC_MEM_FILE_DATA_MAX; j++) {
            proc_mem_file_table[i].data[j] = '\0';
        }
        for (uint32_t j = 0; j < PROC_MEM_FILE_PATTERN_MAX; j++) {
            proc_mem_file_table[i].pattern_valid[j] = 0;
            proc_mem_file_table[i].pattern_byte[j] = 0;
        }
    }
}

struct proc *proc_create(const struct user_space *space) {
    struct proc *p = find_unused_proc();
    if (p == 0) {
        return 0;
    }

    proc_init(p);
    if (space != 0) {
        p->space = user_space_alloc_copy(space);
    } else {
        p->space = (struct user_space *)page_alloc();
        if (p->space != 0) {
            for (uint32_t i = 0; i < PAGE_SIZE; i++) {
                ((uint8_t *)p->space)[i] = 0;
            }
            p->space->refcount = 1;
            p->space->heap_allocated = 1;
        }
    }
    if (p->space == 0) {
        proc_init(p);
        return 0;
    }
    proc_reset_runtime(p);
    if (space != 0 && !proc_alloc_trap_frame(p)) {
        proc_destroy(p);
        return 0;
    }
    p->owns_user_space = true;
    p->state = PROC_READY;
    p->pid = next_pid++;
    p->ppid = 1;
    return p;
}

bool proc_map_trap_frame(struct proc *p) {
    if (p == 0 || p->space == 0) {
        return false;
    }
    if (p->trap_frame_page != 0) {
        return true;
    }
    return proc_alloc_trap_frame(p);
}

struct proc *proc_fork(struct proc *parent, uint64_t flags) {
    if (parent == 0 || parent->space == 0) {
        return 0;
    }

    struct proc *child = find_unused_proc();
    if (child == 0) {
        return 0;
    }

    proc_init(child);
    child->state = PROC_READY;
    if ((flags & 0x00000100ULL) != 0) {
        child->space = parent->space;
        user_space_acquire(child->space);
    } else {
        child->space = user_space_alloc_copy(parent->space);
        if (child->space == 0) {
            proc_init(child);
            return 0;
        }
        if (user_space_has_private_aliases(child->space, parent->space)) {
            kputs("proc: fork copied address space contains private aliases\n");
            user_space_release(child->space);
            proc_init(child);
            return 0;
        }
    }
    child->owns_user_space = true;
    if (!proc_alloc_trap_frame(child)) {
        user_space_release(child->space);
        proc_init(child);
        return 0;
    }

    child->alive = true;
    child->pid = next_pid++;
    child->ppid = parent->pid;
    child->exit_code = 0;
    copy_runtime(child, parent);
    child->child_tid_address = 0;
    child->clear_child_tid_uaddr = 0;
    child->clear_child_tid_owner_pid = 0;
    inherit_pipe_fds(child);
    return child;
}

void proc_exit(struct proc *p, uint64_t encoded_status) {
    if (p == 0 || p->state == PROC_UNUSED || p->state == PROC_ZOMBIE) {
        return;
    }

    proc_clear_child_tid(p);

    p->exit_code = encoded_status;
    p->alive = false;

    proc_close_fds(p);
    proc_release_resources(p);

    if (p->pid == p->tgid) {
        p->state = PROC_ZOMBIE;
    } else {
        p->state = PROC_DEAD;
    }
    for (uint32_t i = 0; i < PROC_MAX_PROCS; i++) {
        struct proc *parent = &proc_table[i];
        if (parent->state == PROC_WAITING && parent->pid == p->ppid) {
            if (parent->wait_target_pid == 0 || parent->wait_target_pid == p->pid) {
                parent->state = PROC_READY; 
            }
        }
    }

    struct proc *direct_parent = find_proc_by_pid_local(p->ppid);
    if (direct_parent != 0) {
        proc_queue_child_signal(direct_parent, p);
    }
}

int proc_is_child_of(struct proc *child, struct proc *parent, uint64_t target_pid) {
    if (child->state == PROC_UNUSED || child == parent) {
        return 0;
    }
    if (child->ppid != parent->pid) {
        return 0;
    }
    if (target_pid == 0) {
        return 1; // 通配符匹配
    }
    return (child->pid == target_pid);
}
int proc_find_waitable_zombie(struct proc *parent, uint64_t target_pid, struct proc **child_out) {
    if (child_out != 0) {
        *child_out = 0;
    }
    int total_children_found = 0; 

    for (uint32_t i = 0; i < PROC_MAX_PROCS; i++) {
        struct proc *child = &proc_table[i];

        if (!proc_is_child_of(child, parent, target_pid)) {
            continue;
        }

        total_children_found++;

        if (child->state == PROC_ZOMBIE) {
            if (child_out != 0) {
                *child_out = child;
            }
            return 1; 
        }
    }
    return (total_children_found > 0) ? 1 : 0;
}

void proc_reap_child(struct proc *child) {
    if (child != 0) {
        proc_destroy(child);
    }
}

void proc_yield(struct proc *p) {
    if (p == 0) {
        return;
    }

    p->state = PROC_READY;
}

void proc_destroy(struct proc *p) {
    if (p == 0) {
        return;
    }

    proc_close_fds(p);
    proc_release_resources(p);
    proc_init(p);
}
